/// <summary>
/// Custom views for Todo items.
/// </summary>
public static class TodoViews
{
    /// <summary>
    /// Details view showing the Todo item with status, metadata, and action buttons.
    /// </summary>
    public static IObservable<UiControl?> Details(LayoutAreaHost host, RenderingContext _)
    {
        return host.Workspace.GetStream<Todo>()
            ?.Select(todos => todos?.FirstOrDefault())
            .Select(todo => BuildTodoDetails(host, todo))
            ?? Observable.Return<UiControl?>(Controls.Markdown("*Loading...*"));
    }

    private static UiControl BuildTodoDetails(LayoutAreaHost host, Todo? todo)
    {
        if (todo == null)
            return Controls.Markdown("*Todo not found*");

        var stack = Controls.Stack.WithStyle(style => style.WithWidth("100%").WithPadding("16px"));

        // Header with status icon and title
        var statusIcon = GetStatusIcon(todo.Status);
        var priorityBadge = GetPriorityBadge(todo.Priority);

        stack = stack.WithView(Controls.Html(
            $"<h1 style=\"margin: 0 0 8px 0; display: flex; align-items: center; gap: 8px;\">{statusIcon} {System.Web.HttpUtility.HtmlEncode(todo.Title)} {priorityBadge}</h1>"));

        // Description
        if (!string.IsNullOrEmpty(todo.Description))
        {
            stack = stack.WithView(Controls.Markdown(todo.Description)
                .WithStyle(style => style.WithMarginBottom("16px").WithColor("var(--neutral-foreground-hint)")));
        }

        // Metadata table
        var metadata = new System.Text.StringBuilder();
        metadata.AppendLine("| Property | Value |");
        metadata.AppendLine("|----------|-------|");
        metadata.AppendLine($"| **Status** | {GetStatusIcon(todo.Status)} {todo.Status} |");
        metadata.AppendLine($"| **Category** | {todo.Category} |");
        metadata.AppendLine($"| **Priority** | {GetPriorityLabel(todo.Priority)} |");
        metadata.AppendLine($"| **Assignee** | {todo.Assignee ?? "Unassigned"} |");
        if (todo.DueDate.HasValue)
            metadata.AppendLine($"| **Due Date** | {todo.DueDate.Value:yyyy-MM-dd} {GetDueDateIndicator(todo.DueDate.Value, todo.Status)} |");
        metadata.AppendLine($"| **Created** | {todo.CreatedAt:yyyy-MM-dd HH:mm} |");
        if (todo.CompletedAt.HasValue)
            metadata.AppendLine($"| **Completed** | {todo.CompletedAt.Value:yyyy-MM-dd HH:mm} |");

        stack = stack.WithView(Controls.Markdown(metadata.ToString())
            .WithStyle(style => style.WithMarginBottom("16px")));

        // Action buttons based on status
        stack = stack.WithView(BuildActionButtons(host, todo));

        return stack;
    }

    private static UiControl BuildActionButtons(LayoutAreaHost host, Todo todo)
    {
        var buttonStack = Controls.Stack
            .WithOrientation(Orientation.Horizontal)
            .WithStyle(style => style.WithGap("8px").WithMarginTop("16px").WithFlexWrap("wrap"));

        var (primaryLabel, primaryStatus) = GetPrimaryAction(todo.Status);
        if (primaryStatus.HasValue)
        {
            buttonStack = buttonStack.WithView(
                Controls.Button(primaryLabel)
                    .WithAppearance(Appearance.Accent)
                    .WithClickAction(_ =>
                    {
                        UpdateTodoStatus(host, todo, primaryStatus.Value);
                        return System.Threading.Tasks.Task.CompletedTask;
                    }));
        }

        // Secondary actions
        foreach (var (label, status) in GetSecondaryActions(todo.Status))
        {
            buttonStack = buttonStack.WithView(
                Controls.Button(label)
                    .WithAppearance(Appearance.Neutral)
                    .WithClickAction(_ =>
                    {
                        UpdateTodoStatus(host, todo, status);
                        return System.Threading.Tasks.Task.CompletedTask;
                    }));
        }

        return buttonStack;
    }

    private static (string Label, TodoStatus? Status) GetPrimaryAction(TodoStatus status) => status switch
    {
        TodoStatus.Pending => ("Start", TodoStatus.InProgress),
        TodoStatus.InProgress => ("Complete", TodoStatus.Completed),
        TodoStatus.InReview => ("Approve", TodoStatus.Completed),
        TodoStatus.Blocked => ("Unblock", TodoStatus.InProgress),
        TodoStatus.Completed => ("Reopen", TodoStatus.InProgress),
        _ => ("Unknown", null)
    };

    private static IEnumerable<(string Label, TodoStatus Status)> GetSecondaryActions(TodoStatus status)
    {
        switch (status)
        {
            case TodoStatus.Pending:
                yield return ("Complete", TodoStatus.Completed);
                yield return ("Block", TodoStatus.Blocked);
                break;
            case TodoStatus.InProgress:
                yield return ("Pause", TodoStatus.Pending);
                yield return ("Send for Review", TodoStatus.InReview);
                yield return ("Block", TodoStatus.Blocked);
                break;
            case TodoStatus.InReview:
                yield return ("Return to Progress", TodoStatus.InProgress);
                yield return ("Block", TodoStatus.Blocked);
                break;
            case TodoStatus.Blocked:
                yield return ("Return to Pending", TodoStatus.Pending);
                break;
            case TodoStatus.Completed:
                // No secondary actions for completed
                break;
        }
    }

    private static void UpdateTodoStatus(LayoutAreaHost host, Todo todo, TodoStatus newStatus)
    {
        var updatedTodo = todo with
        {
            Status = newStatus,
            CompletedAt = newStatus == TodoStatus.Completed ? DateTimeOffset.UtcNow : null
        };

        var changeRequest = new DataChangeRequest().WithUpdates(updatedTodo);
        host.Hub.Post(changeRequest, o => o.WithTarget(host.Hub.Address));
    }

    /// <summary>
    /// Thumbnail view for catalog listings - compact card format.
    /// </summary>
    public static IObservable<UiControl?> Thumbnail(LayoutAreaHost host, RenderingContext _)
    {
        var hubPath = host.Hub.Address.ToString();

        return host.Workspace.GetStream<Todo>()
            ?.Select(todos => todos?.FirstOrDefault())
            .Select(todo => BuildThumbnail(todo, hubPath))
            ?? Observable.Return<UiControl?>(null);
    }

    private static UiControl BuildThumbnail(Todo? todo, string hubPath)
    {
        if (todo == null)
            return Controls.Html("");

        var statusIcon = GetStatusIcon(todo.Status);
        var priorityBadge = GetPriorityBadge(todo.Priority);
        var dueDateInfo = todo.DueDate.HasValue
            ? $"<div style=\"font-size: 11px; color: var(--neutral-foreground-hint);\">Due: {todo.DueDate.Value:MMM dd} {GetDueDateIndicator(todo.DueDate.Value, todo.Status)}</div>"
            : "";

        var statusColor = GetStatusColor(todo.Status);

        return Controls.Html($@"
            <a href=""/{hubPath}"" style=""text-decoration: none; color: inherit; display: block;"">
                <div style=""padding: 12px; border: 1px solid var(--neutral-stroke-rest); border-radius: 8px; background: var(--neutral-layer-2); border-left: 3px solid {statusColor};"">
                    <div style=""display: flex; align-items: center; gap: 8px; margin-bottom: 4px;"">
                        <span style=""font-size: 16px;"">{statusIcon}</span>
                        <span style=""font-weight: 600; flex: 1; overflow: hidden; text-overflow: ellipsis; white-space: nowrap;"">{System.Web.HttpUtility.HtmlEncode(todo.Title)}</span>
                        {priorityBadge}
                    </div>
                    <div style=""font-size: 12px; color: var(--neutral-foreground-hint); margin-bottom: 4px;"">{todo.Category}</div>
                    <div style=""display: flex; justify-content: space-between; align-items: center;"">
                        <span style=""font-size: 11px; color: var(--neutral-foreground-hint);"">{todo.Assignee ?? "Unassigned"}</span>
                        {dueDateInfo}
                    </div>
                </div>
            </a>");
    }

    private static string GetStatusIcon(TodoStatus status) => status switch
    {
        TodoStatus.Pending => "\u23f3",
        TodoStatus.InProgress => "\ud83d\udd04",
        TodoStatus.InReview => "\ud83d\udc41\ufe0f",
        TodoStatus.Completed => "\u2705",
        TodoStatus.Blocked => "\ud83d\udeab",
        _ => "\u2753"
    };

    private static string GetStatusColor(TodoStatus status) => status switch
    {
        TodoStatus.Pending => "#ffc107",
        TodoStatus.InProgress => "#0d6efd",
        TodoStatus.InReview => "#6f42c1",
        TodoStatus.Completed => "#198754",
        TodoStatus.Blocked => "#dc3545",
        _ => "#6c757d"
    };

    private static string GetPriorityBadge(TaskPriority priority) => priority switch
    {
        TaskPriority.Critical => "<span style=\"background: #dc3545; color: white; padding: 2px 6px; border-radius: 4px; font-size: 10px; font-weight: 600;\">CRITICAL</span>",
        TaskPriority.High => "<span style=\"background: #fd7e14; color: white; padding: 2px 6px; border-radius: 4px; font-size: 10px; font-weight: 600;\">HIGH</span>",
        TaskPriority.Medium => "",
        TaskPriority.Low => "<span style=\"background: #6c757d; color: white; padding: 2px 6px; border-radius: 4px; font-size: 10px;\">LOW</span>",
        _ => ""
    };

    private static string GetPriorityLabel(TaskPriority priority) => priority switch
    {
        TaskPriority.Critical => "\ud83d\udea8 Critical",
        TaskPriority.High => "\ud83d\udd25 High",
        TaskPriority.Medium => "\u2796 Medium",
        TaskPriority.Low => "\u2b07\ufe0f Low",
        _ => priority.ToString()
    };

    private static string GetDueDateIndicator(DateTimeOffset dueDate, TodoStatus status)
    {
        if (status == TodoStatus.Completed) return "";

        var today = DateTimeOffset.Now.Date;
        var dueDateOnly = dueDate.Date;

        if (dueDateOnly < today)
            return "<span style=\"color: #dc3545; font-weight: 600;\">OVERDUE</span>";
        if (dueDateOnly == today)
            return "<span style=\"color: #fd7e14; font-weight: 600;\">TODAY</span>";
        if (dueDateOnly == today.AddDays(1))
            return "<span style=\"color: #ffc107;\">Tomorrow</span>";

        return "";
    }
}
